CREATE MATERIALIZED VIEW public.metrics_mv AS
 SELECT date_trunc('hour'::text, ts) AS date_hour,
    (count(*))::integer AS sample_count,
    trunc((avg(cpu_percent))::numeric, 2) AS avg_cpu_percent,
    trunc((min(cpu_percent))::numeric, 2) AS min_cpu_percent,
    trunc((max(cpu_percent))::numeric, 2) AS max_cpu_percent,
    trunc((avg(avg_latency_ms))::numeric, 2) AS avg_latency_ms,
    trunc((min(avg_latency_ms))::numeric, 2) AS min_latency_ms,
    trunc((max(avg_latency_ms))::numeric, 2) AS max_latency_ms,
    (trunc(avg(memory_bytes), 0))::bigint AS avg_memory_bytes,
    min(memory_bytes) AS min_memory_bytes,
    max(memory_bytes) AS max_memory_bytes,
    (max(requests_total))::integer AS max_requests_total,
    (max(errors_total))::integer AS max_errors_total
   FROM public.metrics_entry m
  GROUP BY (date_trunc('hour'::text, ts))
  WITH NO DATA;


